INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 1, 'Preheat oven to 350°F (175°C) and grease an 8x8 inch baking pan.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 2, 'Peel and chop sweet potatoes, then steam or boil until tender (about 15-20 minutes).');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 3, 'Mash sweet potatoes until completely smooth. Measure 1 cup of mashed sweet potatoes.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 4, 'In a large bowl, whisk together the mashed sweet potatoes, eggs, vegetable oil, and vanilla extract.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 5, 'In a separate bowl, sift together flour, cocoa powder, sugar, baking powder, and salt.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 6, 'Gradually fold the dry ingredients into the wet mixture until just combined. Do not overmix.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 7, 'Pour batter into the prepared baking pan and spread evenly.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 8, 'Bake for 25-30 minutes until a toothpick inserted in center comes out with a few moist crumbs.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 9, 'Let cool completely in the pan before cutting into squares.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (45, 10, 'Store in an airtight container for up to 5 days, or refrigerate for longer storage.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 1, 'Warm the milk to 110°F (43°C) and dissolve the yeast and 1 tablespoon of sugar. Let sit for 5 minutes until foamy.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 2, 'In a large bowl, combine mashed potatoes, remaining sugar, melted butter, egg, and vanilla extract.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 3, 'Add the yeast mixture to the potato mixture and stir well.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 4, 'In a separate bowl, whisk together flour, nutmeg, cinnamon, and salt.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 5, 'Gradually add the flour mixture to the wet ingredients, mixing until a soft dough forms.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 6, 'Turn dough onto a floured surface and knead for 5-7 minutes until smooth and elastic.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 7, 'Place dough in a greased bowl, cover with a damp cloth, and let rise in a warm place for 1 hour or until doubled.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 8, 'Roll out the dough to 1/2 inch thickness on a floured surface.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 9, 'Cut into donuts using a donut cutter or two round cutters (one large, one small for the hole).');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 10, 'Place cut donuts on a floured baking sheet, cover, and let rise for 30 minutes.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 11, 'Heat vegetable oil to 350°F (175°C) in a deep pan or Dutch oven.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 12, 'Fry donuts 2-3 at a time for 1-2 minutes per side until golden brown.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 13, 'Remove with a slotted spoon and drain on paper towels.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 14, 'While warm, dust generously with powdered sugar or dip in glaze if desired.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (46, 15, 'Best served fresh, but can be stored in an airtight container for up to 2 days.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 1, 'Peel and cube purple potatoes, then boil until fork-tender (about 15 minutes).');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 2, 'Drain potatoes and mash until completely smooth with no lumps. Let cool completely.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 3, 'Measure 1 cup of cooled mashed purple potatoes and place in a blender.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 4, 'Add milk, heavy cream, sugar, honey, vanilla extract, and salt to the blender.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 5, 'Add ube extract if using for enhanced purple color and flavor.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 6, 'Blend on high for 1-2 minutes until completely smooth and purple in color.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 7, 'Transfer mixture to a bowl and refrigerate for at least 2 hours or overnight until thoroughly chilled.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 8, 'Pour chilled mixture into an ice cream maker and churn according to manufacturer''s instructions (usually 20-25 minutes).');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 9, 'Transfer to a freezer-safe container and freeze for at least 4 hours to firm up.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (47, 10, 'Let sit at room temperature for 5 minutes before scooping and serving.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 1, 'Preheat oven to 375°F (190°C) and grease a 9x13 inch baking dish.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 2, 'Peel and thinly slice potatoes. Soak in cold water for 10 minutes, then drain and pat dry.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 3, 'Peel, core, and slice apples into similar thickness as potatoes.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 4, 'In a large bowl, toss together potato slices, apple slices, lemon juice, vanilla extract, and half the cinnamon.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 5, 'Layer the potato-apple mixture evenly in the prepared baking dish.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 6, 'In a bowl, combine flour, oats, brown sugar, remaining cinnamon, nutmeg, and salt.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 7, 'Cut in the cold butter using a pastry cutter or fork until mixture resembles coarse crumbs.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 8, 'Sprinkle the crumble topping evenly over the potato-apple layer.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 9, 'Bake for 45-50 minutes until topping is golden brown and fruit is bubbling.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (48, 10, 'Let cool for 15 minutes before serving. Serve warm with vanilla ice cream if desired.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 1, 'Ensure mashed potatoes are completely smooth with no lumps, and at room temperature.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 2, 'In a large bowl, combine mashed potatoes, peanut butter, and vanilla extract. Mix until smooth.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 3, 'In a separate bowl, sift together powdered sugar, cocoa powder, and salt.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 4, 'Gradually add the dry mixture to the potato mixture, stirring continuously.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 5, 'Add milk 1 tablespoon at a time if mixture is too dry to come together.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 6, 'Fold in chopped walnuts if using.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 7, 'Line an 8x8 inch pan with parchment paper, leaving overhang for easy removal.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 8, 'Press the fudge mixture firmly and evenly into the prepared pan.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 9, 'Refrigerate for at least 2 hours until firm.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (49, 10, 'Lift out using parchment overhang and cut into small squares. Store refrigerated.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 1, 'Ensure mashed potatoes are completely smooth, unsalted, and at room temperature.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 2, 'Mix mashed potatoes with vanilla extract and salt in a large bowl.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 3, 'Gradually add powdered sugar, 1 cup at a time, mixing until a thick dough forms.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 4, 'You may need slightly more or less powdered sugar depending on potato moisture.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 5, 'Divide dough into two portions for easier handling.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 6, 'On a surface dusted with powdered sugar, roll out one portion into a rectangle about 1/4 inch thick.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 7, 'Spread half the peanut butter evenly over the rolled dough.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 8, 'Sprinkle with half the shredded coconut if using.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 9, 'Carefully roll up the dough tightly like a jelly roll, starting from the long edge.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 10, 'Repeat with the second portion of dough and remaining peanut butter/coconut.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 11, 'Wrap each roll in plastic wrap and refrigerate for at least 1 hour to firm up.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 12, 'Slice into 1/2 inch thick rounds using a sharp knife.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction) VALUES (50, 13, 'Store in an airtight container in the refrigerator for up to 1 week.');